revision.text:
/* {{pp-template}} */
.dmbox {
	display: flex;
	align-items: center;
	clear: both;
	margin: 0.9em 1em;
	border-top: 1px solid #ccc;
	border-bottom: 1px solid #ccc;
	padding: 0.25em 0.35em;
	font-style: italic;
}

.dmbox > * {
	flex-shrink: 0;
	margin: 0 0.25em;
}

.dmbox-body {
	flex-grow: 1;
	flex-shrink: 1;
	padding: 0.1em 0;
}

.dmbox-invalid-type {
	text-align: center;
}

